// is brittle, so exempt this generated module. The hand-written sibling
// `plain_dump.rs` mirrors the same logic and stays fully linted.
#![allow(clippy::all)]

include!(concat!(env!("OUT_DIR"), "/latex_dump_loader.rs"));
